import{_ as e,o as r,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Glossary","description":"","frontmatter":{"title":"Glossary","slug":"glossary"},"headers":[],"relativePath":"marketer-hub/glossary.md","filePath":"marketer-hub/glossary.md"}'),s={name:"marketer-hub/glossary.md"};function i(d,t,o,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[n('<p>Use this glossary to learn about terms commonly used in Branch. To submit a term to be added, submit feedback at the bottom of the article.</p><h2 id="deep-linking" tabindex="-1">Deep linking <a class="header-anchor" href="#deep-linking" aria-label="Permalink to &quot;Deep linking&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Related Terms</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Universal Resource Identifier (URI)</strong></td><td></td><td>A unique address that apps register with the operating system to handle specific link formats (like http:// or custom schemes). When a user clicks a link with a registered URI, the OS opens the associated app. If no app is registered for that URI, the OS displays an error message.</td></tr><tr><td><strong>Deep Linking</strong></td><td></td><td>Links that direct users to specific content within a mobile app rather than just opening the app&#39;s home screen. When users click a deep link and have the app installed, they&#39;re taken directly to the relevant content shown in the link.</td></tr><tr><td><strong>Universal Links</strong></td><td></td><td>Apple&#39;s iOS deep linking technology that opens apps seamlessly without showing a permission dialog. If the app isn&#39;t installed, users are redirected to a web browser. This technology works primarily in Apple platforms like Safari and iMessage.</td></tr><tr><td></td><td>Apple App Site Association (AASA)</td><td>A JSON file that websites must host to enable Universal Links. The AASA file tells iOS which app should open when users click links from that domain.</td></tr><tr><td><strong>Android App Links</strong></td><td></td><td>Android&#39;s deep linking technology that opens apps directly without showing the app selection dialog. If the app isn&#39;t installed, users are redirected to a web browser.</td></tr><tr><td></td><td>Digital Asset Links (DAL)</td><td>A JSON file that websites must host to enable Android App Links. The DAL file tells Android which app should open when users click links from that domain.</td></tr><tr><td><strong>Facebook App Links</strong></td><td></td><td>Facebook&#39;s deep linking standard that uses special HTML meta tags on web pages to open apps through URI schemes when links are clicked within Facebook.</td></tr><tr><td><strong>Chrome Intents</strong></td><td></td><td>A deep linking method for Android Chrome browsers that uses special HTML code embedded in web pages to open apps directly.</td></tr><tr><td><strong>Deferred Deep Link</strong></td><td></td><td>A deep link that works even when users don&#39;t have the app installed. After clicking the link, users are taken to download the app, then automatically directed to the intended content on first launch.</td></tr><tr><td><strong>App Indexing</strong></td><td></td><td>Google&#39;s legacy system that creates a 1:1 mapping between website URLs and app content. No longer recommended by Google.</td></tr></tbody></table><h2 id="matching-and-attribution" tabindex="-1">Matching and attribution <a class="header-anchor" href="#matching-and-attribution" aria-label="Permalink to &quot;Matching and attribution&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Related Terms</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Browser Cookie</strong></td><td></td><td>A small data file stored by web browsers to track user identity and behavior. Cookies are isolated to each browser and cannot be accessed by other browsers or apps, limiting their use for cross-platform attribution.</td></tr><tr><td><strong>Query Parameter</strong></td><td></td><td>Data appended to the end of a URL after a question mark to pass information about the link source. For example, in &quot;<a href="https://www.espn.com/?utm%5C_medium=email" target="_blank" rel="noreferrer">https://www.espn.com/?utm\\_medium=email</a>&quot;, the query parameter &quot;utm_medium=email&quot; indicates the link came from an email campaign.</td></tr><tr><td><strong>Device ID</strong></td><td></td><td>A unique identifier provided by iOS and Android that lets app developers track individual devices. Device IDs are only accessible within apps, not from web browsers.</td></tr><tr><td></td><td>IDFA</td><td>Apple&#39;s Identifier for Advertisers. A device-level identifier that works across all apps on iOS devices, allowing ad networks to track users and show targeted ads. Users can reset their IDFA or opt out of tracking at any time.</td></tr><tr><td></td><td>IDFV</td><td>Apple&#39;s Identifier for Vendor. A persistent identifier that remains the same for all apps from the same developer (like Facebook and Facebook Messenger) but differs for apps from different developers. Used as a fallback when IDFA is unavailable.</td></tr><tr><td><strong>Attribution</strong></td><td></td><td>The practice of identifying which marketing campaigns drive specific user actions, allowing marketers to measure campaign effectiveness and ROI. Attribution can track web-only, app-only, or cross-platform user behavior.</td></tr><tr><td><strong>Biased Attribution</strong></td><td></td><td>Attribution data from platforms that have a financial interest in claiming credit for conversions (like ad networks reporting on their own ad performance). Third-party attribution providers offer more objective measurement.</td></tr><tr><td><strong>Attribution Window</strong></td><td></td><td>The time period during which a conversion (like an app install) can be credited to a marketing touchpoint (like a link click). For example, a 7-day attribution window means installs within 7 days of a click are attributed to that click.</td></tr><tr><td><strong>People-Based Attribution</strong></td><td></td><td>Attribution that tracks individual users across devices and platforms, preventing the same person from being counted multiple times when they switch between mobile and web.</td></tr><tr><td><strong>Last-Touch Attribution</strong></td><td></td><td>An attribution model that gives 100% credit to the most recent marketing touchpoint before a conversion.</td></tr><tr><td><strong>Multi-Touch Attribution</strong></td><td></td><td>An attribution model that distributes credit across all marketing touchpoints that contributed to a conversion.</td></tr><tr><td><strong>View-Through Attribution</strong></td><td></td><td>Attribution that credits conversions to ad impressions even when users didn&#39;t click the ad, measuring the impact of simply seeing an advertisement.</td></tr><tr><td><strong>Monthly Active Users (MAU)</strong></td><td></td><td>The number of unique users who engaged with an app at least once during a calendar month, measured at the device level.</td></tr></tbody></table><h2 id="branch-platform-terms" tabindex="-1">Branch platform terms <a class="header-anchor" href="#branch-platform-terms" aria-label="Permalink to &quot;Branch platform terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Related Terms</th><th>Definition</th></tr></thead><tbody><tr><td><strong>SDK</strong></td><td></td><td>Software Development Kit. A package of tools and code that developers integrate into their apps to add specific functionality. Branch provides SDKs for iOS, Android, web, and other platforms to enable deep linking and attribution.</td></tr><tr><td><strong>API</strong></td><td></td><td>Application Programming Interface. A set of protocols that allows different software systems to communicate with each other. SDKs typically include APIs but also provide additional tools and documentation to make integration easier.</td></tr><tr><td><strong>Branch Dashboard</strong></td><td></td><td>The web interface where users manage their Branch account, view analytics, create links and banners, configure integrations, manage team members, and export data.</td></tr><tr><td></td><td>Liveview</td><td>A real-time dashboard showing event data as it happens.</td></tr><tr><td></td><td>Short Link</td><td>A Branch link created directly in the dashboard interface.</td></tr><tr><td><strong>App Link</strong></td><td></td><td>Branch&#39;s default link domain provided to all customers. App links direct users to apps or specific app content and require an active website to function properly.</td></tr><tr><td><strong>Short Link</strong></td><td></td><td>A Branch link with a custom alias added to the end of the domain for easy sharing and recognition. For example, in &quot;<a href="https://espn.app.link/sms" target="_blank" rel="noreferrer">https://espn.app.link/sms</a>&quot;, &quot;sms&quot; is the alias.</td></tr><tr><td><strong>Dynamic Long Link</strong></td><td></td><td>A Branch link that includes multiple query parameters to pass data directly in the URL. For example, &quot;<a href="https://espn.app.link?example=one&amp;~campaign=test" target="_blank" rel="noreferrer">https://espn.app.link?example=one&amp;~campaign=test</a>&quot; sends key-value pairs into the app without requiring dashboard configuration.</td></tr><tr><td><strong>3p Link</strong></td><td></td><td>Third-party link. A Branch link formatted to meet the specific requirements of external platforms like ad networks or SMS providers.</td></tr></tbody></table><h2 id="branch-analytics" tabindex="-1">Branch analytics <a class="header-anchor" href="#branch-analytics" aria-label="Permalink to &quot;Branch analytics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Event Ontology (EO)</strong></td><td>Branch&#39;s standardized event taxonomy for consistent analytics tracking across platforms.</td></tr><tr><td><strong>Pageview</strong></td><td>Measured each time a webpage loads with the Branch Web SDK initialized.</td></tr><tr><td><strong>Branch CTA View (View)</strong></td><td>Counted when a Branch banner or Deepview loads and displays in a user&#39;s browser.</td></tr><tr><td><strong>Web Session Start</strong></td><td>Measured when a webpage with the Branch Web SDK opens in a new tab or when a user arrives via a Branch link.</td></tr><tr><td><strong>Impression</strong></td><td>Counted when a paid advertisement displays on a user&#39;s screen, tracked through Branch&#39;s Mobile Measurement Partner (MMP) API or Branch Links.</td></tr><tr><td><strong>Click</strong></td><td>Counted each time a user clicks a Branch link.</td></tr><tr><td><strong>Install</strong></td><td>Measured the first time a user opens an app after downloading it to a device.</td></tr><tr><td><strong>Open</strong></td><td>Counted each time a user opens an app after the initial install.</td></tr><tr><td><strong>Reinstall</strong></td><td>Measured when a user downloads and opens an app they previously uninstalled.</td></tr><tr><td><strong>Unique</strong></td><td>Events deduplicated at the user level. For example, if the same user clicks a link twice, it counts as one unique click.</td></tr><tr><td><strong>Click-to-Install (CTI)</strong></td><td>The percentage of link clicks that result in app installs, calculated as installs divided by clicks.</td></tr><tr><td><strong>Click-Through Rate (CTR)</strong></td><td>The percentage of ad impressions or views that result in clicks, calculated as clicks divided by impressions.</td></tr><tr><td><strong>Click-to-Open (CTO)</strong></td><td>The percentage of link clicks that result in app opens, calculated as opens divided by clicks.</td></tr></tbody></table><h2 id="branch-product-specific-terminology" tabindex="-1">Branch product-specific terminology <a class="header-anchor" href="#branch-product-specific-terminology" aria-label="Permalink to &quot;Branch product-specific terminology&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Related Terms</th><th>Definition</th></tr></thead><tbody><tr><td><strong>In-App Sharing</strong></td><td></td><td>Using Branch SDKs to let users share deep links from within your app or website to drive conversions.</td></tr><tr><td></td><td>Referrals</td><td>Branch&#39;s reward tracking system that works with in-app sharing to reward users when their shared links drive conversions.</td></tr><tr><td><strong>App-to-App</strong></td><td></td><td>Using Branch Links within one app to route users to content in a different app.</td></tr><tr><td><strong>Event Tracking</strong></td><td></td><td>Using Branch SDKs to track custom user actions (like purchases or signups) and connect them to marketing campaigns through Branch&#39;s attribution engine.</td></tr><tr><td></td><td>Cohort Analysis</td><td>Grouping users by shared characteristics or behaviors within a time period (like &quot;users who signed up last week&quot;) to compare both engagement volume and quality across campaigns.</td></tr><tr><td><strong>Web-to-App</strong></td><td></td><td>Branch products that drive traffic from websites into mobile apps.</td></tr><tr><td></td><td>Journeys</td><td>Branch&#39;s smart banners that display on web pages to encourage users to install or open your app.</td></tr><tr><td></td><td>Accelerated Mobile Pages (AMPs)</td><td>Google&#39;s framework for building fast-loading mobile web pages. While AMP pages load quickly and rank well in search, standard links within AMP content redirect to search results rather than deeper content.</td></tr><tr><td></td><td>Text Me the App (TMTA)</td><td>A Branch Web SDK feature for desktop websites that lets users text themselves a download link to get your app on their phone.</td></tr><tr><td></td><td>Deepviews</td><td>Dynamically generated web pages that preview app content before users install or open the app, built automatically from data in Branch Links.</td></tr><tr><td><strong>Data Feeds</strong></td><td></td><td>Branch features that enable advanced data export capabilities.</td></tr><tr><td></td><td>Webhooks</td><td>Real-time server notifications triggered when specific events occur, also called &quot;postbacks.&quot;</td></tr><tr><td></td><td>Data Integration</td><td>Sending Branch event data to third-party analytics platforms through automated webhooks. Event Ingestion is the reverse: importing events from third parties into Branch.</td></tr><tr><td></td><td>Export API</td><td>An API endpoint that lets you download user-level data as CSV files for any day within the past week.</td></tr><tr><td></td><td>Query API</td><td>An API endpoint to retrieve the same campaign-level analytics data shown in the Branch dashboard.</td></tr><tr><td><strong>Ads</strong></td><td></td><td>Branch&#39;s advertising product that enables deep linking in ads and provides last-touch attribution across all ad networks and platforms.</td></tr><tr><td></td><td>Publisher</td><td>A website or app that sells advertising space on their platform.</td></tr><tr><td></td><td>Advertiser</td><td>A company that buys advertising space to promote their products or services.</td></tr><tr><td></td><td>Ad Networks</td><td>Companies that connect advertisers with publishers who want to display ads.</td></tr><tr><td></td><td>Supply-Side Platform (SSP)</td><td>A platform that helps publishers manage, sell, and optimize their ad inventory by listing it and collecting bids from advertisers.</td></tr><tr><td></td><td>Demand-Side Platform (DSP)</td><td>A platform that lets advertisers manage ad purchases across multiple ad networks and publishers through a single interface.</td></tr><tr><td></td><td>SAN, non-SAN</td><td>Self-Attributing Networks are ad platforms (like Facebook or Google) that track and attribute conversions within their own ecosystems. Non-SANs rely on third-party attribution providers like Branch.</td></tr><tr><td></td><td>MMP</td><td>Mobile Measurement Partner. A designation used by Self-Attributing Networks to identify approved third parties that can access their private APIs.</td></tr><tr><td></td><td>Fraud</td><td>Malicious activity that artificially generates ad engagement to steal advertising budgets. Branch provides fraud detection to identify suspicious activity patterns.</td></tr><tr><td></td><td>Cost Ingestion</td><td>Branch&#39;s ability to import ad spend data from select ad networks and display it alongside campaign performance metrics in the dashboard.</td></tr><tr><td><strong>Email</strong></td><td></td><td>Branch&#39;s email product that tracks Branch link usage in marketing emails and sends click data back to email service providers for reporting.</td></tr><tr><td></td><td>ESP</td><td>Email Service Provider. Marketing platforms like Salesforce that send large-scale email campaigns.</td></tr><tr><td></td><td>CTD</td><td>Click Tracking Domain. A redirect applied to email links to track clicks, typically by email service providers. Redirects can prevent iOS Universal Links from working properly.</td></tr><tr><td></td><td>Simplified Integration</td><td>A Branch email integration method that uses a CNAME pointing to Branch to automate setup. Includes Auto-Branchify, which automatically converts standard web links to Branch Links in emails.</td></tr></tbody></table><h2 id="other-related-terminology" tabindex="-1">Other related terminology <a class="header-anchor" href="#other-related-terminology" aria-label="Permalink to &quot;Other related terminology&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Ad Stacking</strong></td><td>A fraud technique where multiple ads are layered in one placement, with only the top ad visible. Advertisers are charged for all ads in the stack despite users seeing only one.</td></tr><tr><td><strong>Click Hijacking</strong></td><td>Fraud where malware embedded in legitimate apps detects real ad clicks and immediately generates fake clicks, stealing credit for the conversion.</td></tr><tr><td><strong>Click Injection</strong></td><td>Similar to click hijacking. Malicious apps detect when users download legitimate apps and report fake clicks to claim credit for those installs.</td></tr><tr><td><strong>Click Flooding</strong></td><td>Fraud where bots generate massive numbers of clicks across many device IDs, aiming to claim credit for organic installs by being the last recorded click before installation.</td></tr><tr><td><strong>Device ID Reset Fraud</strong></td><td>Fraud exploiting Apple&#39;s IDFA reset feature to repeatedly install, use, and uninstall apps, generating multiple install events from a single device.</td></tr><tr><td><strong>Mobile Ad Fraud</strong></td><td>Any fraudulent activity designed to steal advertising budgets, typically by falsely claiming credit for conversions that would have happened organically.</td></tr><tr><td><strong>Emulated Devices</strong></td><td>Mobile operating systems running on non-mobile hardware, useful for app testing but also exploitable for fraud through scripted interactions.</td></tr><tr><td><strong>Phone Farm</strong></td><td>Operations using multiple physical devices simultaneously to artificially generate app activity or engagement at scale.</td></tr><tr><td><strong>Cookie Stuffing</strong></td><td>Illegal practice where third-party cookies from unrelated websites are placed in users&#39; browsers without their knowledge to falsely claim affiliate commissions.</td></tr><tr><td><strong>ARPU</strong></td><td>Average Revenue Per User. Total revenue divided by number of users over a time period (typically monthly or annually), used to assess app profitability.</td></tr><tr><td><strong>CPA</strong></td><td>Cost Per Action. Total campaign cost divided by the number of user actions (like purchases or signups), measuring the cost of acquiring each conversion.</td></tr><tr><td><strong>CPC</strong></td><td>Cost Per Click. Total ad cost divided by total clicks, measuring what advertisers pay for each click on their ads.</td></tr><tr><td><strong>CPI</strong></td><td>Cost Per Install. Total ad spend divided by number of app installs, measuring how much it costs to acquire each new app user.</td></tr><tr><td><strong>LTV</strong></td><td>Lifetime Value. The total revenue a user is expected to generate over their entire relationship with your app or business.</td></tr><tr><td><strong>Retention Rate</strong></td><td>The percentage of users who continue using an app after installation, calculated by dividing active users by total installs over a time period.</td></tr><tr><td><strong>KPI</strong></td><td>Key Performance Indicator. Metrics used to measure progress toward business objectives, typically focused on cost reduction, revenue growth, customer satisfaction, or process improvement.</td></tr><tr><td><strong>K-Factor</strong></td><td>A measure of app virality showing how many new users each existing user brings in through sharing, calculated as: (install→activation rate) × (activation→share rate) × (share→new install rate).</td></tr><tr><td><strong>Matching Accuracy</strong></td><td>The confidence level (expressed as a percentage) that an attribution provider has in correctly linking user behavior across web and mobile app platforms.</td></tr><tr><td><strong>Conversion Rate</strong></td><td>The percentage of users who complete a desired action, calculated as conversions divided by total users or sessions.</td></tr><tr><td><strong>Fragmentation</strong></td><td>The challenge of deep linking across platforms, where each major platform (iOS, Android, Facebook, etc.) has different standards and requirements.</td></tr><tr><td><strong>Retargeting</strong></td><td>Showing targeted ads to users based on their previous interactions with your app or website, enabled by people-based attribution that identifies users across sessions.</td></tr><tr><td><strong>Dormant User</strong></td><td>Users who were previously active but haven&#39;t engaged with your app or website for an extended period.</td></tr><tr><td><strong>User Agent</strong></td><td>Information sent by browsers identifying the device type and operating system, used by servers to optimize content delivery and by attribution systems for device matching.</td></tr><tr><td><strong>Hosted Deep Links</strong></td><td>Deep links managed through a platform that handles all the different deep linking standards and technologies across platforms.</td></tr><tr><td><strong>Mobile Banners and Interstitials</strong></td><td>Web-based call-to-action messages encouraging users to open or install an app. Banners occupy a small portion of the screen, while interstitials cover most or all of it. Smart banners automatically display &quot;Open&quot; or &quot;Install&quot; based on app installation status.</td></tr></tbody></table>',13)])])}const u=e(s,[["render",i]]);export{g as __pageData,u as default};
